#include <iostream>
using namespace std;

int* createOnStack() {
    int x = 42;
    // return &x;  // WRONG: x is destroyed when function returns
    return nullptr;
}

int* createOnHeap() {
    int* p = new int(42);
    return p;  // OK: heap memory persists
}

int main() {
    int* stackPtr = createOnStack();
    cout << "Stack pointer: " << stackPtr << endl;  // nullptr

    int* heapPtr = createOnHeap();
    cout << "Heap value: " << *heapPtr << endl;  // 42
    delete heapPtr;

    // Stack variable
    {
        int local = 100;  // alive only in this block
        cout << "Local: " << local << endl;
    }
    // local is destroyed here

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n;
    cout << "Enter size: ";
    cin >> n;

    // Allocate array on heap
    int* arr = new int[n];

    // Fill with squares
    for (int i = 0; i < n; i++) {
        arr[i] = (i + 1) * (i + 1);
    }

    // Print
    cout << "Squares: ";
    for (int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // Zero-initialized array
    int* zeros = new int[n]();
    cout << "Zeros: ";
    for (int i = 0; i < n; i++) {
        cout << zeros[i] << " ";
    }
    cout << endl;

    delete[] arr;
    delete[] zeros;

    return 0;
}

#include <iostream>
using namespace std;

void leakyFunction() {
    int* p = new int(42);
    cout << "Value: " << *p << endl;
    // Oops! Forgot delete p;
    // Memory is leaked when function returns
}

void overwriteLeak() {
    int* p = new int(10);
    cout << "First: " << *p << endl;
    p = new int(20);           // LEAK: lost pointer to first allocation
    cout << "Second: " << *p << endl;
    delete p;                  // Only frees the second allocation
}

void noLeak() {
    int* p = new int(42);
    cout << "Value: " << *p << endl;
    delete p;                  // Properly freed
    p = nullptr;               // Good practice
}

int main() {
    cout << "--- Leaky function ---" << endl;
    leakyFunction();

    cout << "\n--- Overwrite leak ---" << endl;
    overwriteLeak();

    cout << "\n--- No leak ---" << endl;
    noLeak();

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Student {
    string name;
    int rollNo;
public:
    Student(string n, int r) : name(n), rollNo(r) {
        cout << "Constructor: " << name << " (" << rollNo << ")" << endl;
    }
    ~Student() {
        cout << "Destructor: " << name << " (" << rollNo << ")" << endl;
    }
    void display() {
        cout << name << " - Roll No: " << rollNo << endl;
    }
};

int main() {
    cout << "--- Single object ---" << endl;
    Student* s1 = new Student("Rahul", 101);
    s1->display();
    delete s1;

    cout << "\n--- Array of objects ---" << endl;
    Student* arr = new Student[3]{{"Priya", 201}, {"Arun", 202}, {"Sneha", 203}};
    for (int i = 0; i < 3; i++) {
        arr[i].display();
    }
    delete[] arr;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int rows = 3, cols = 4;

    // Allocate 2D array
    int** matrix = new int*[rows];
    for (int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
    }

    // Fill with values
    int val = 1;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = val++;
        }
    }

    // Print
    cout << "Matrix:" << endl;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << matrix[i][j] << "\t";
        }
        cout << endl;
    }

    // Deallocate (reverse order: rows first, then array of pointers)
    for (int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    return 0;
}

#include <iostream>
using namespace std;

class DynamicArray {
    int* data;
    int capacity;
public:
    DynamicArray(int n) : capacity(n), data(new int[n]()) {
        cout << "Allocated " << n << " elements" << endl;
    }

    ~DynamicArray() {
        delete[] data;
        cout << "Freed " << capacity << " elements" << endl;
    }

    int& operator[](int index) {
        return data[index];
    }

    int size() const { return capacity; }
};

void processData() {
    DynamicArray arr(5);
    for (int i = 0; i < arr.size(); i++) {
        arr[i] = (i + 1) * 10;
    }
    cout << "Data: ";
    for (int i = 0; i < arr.size(); i++) {
        cout << arr[i] << " ";
    }
    cout << endl;
    // No manual delete needed!
    // Destructor runs automatically when arr goes out of scope
}

int main() {
    processData();
    cout << "Function returned safely" << endl;
    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Resource {
    string name;
public:
    Resource(string n) : name(n) {
        cout << "Created: " << name << endl;
    }
    ~Resource() {
        cout << "Destroyed: " << name << endl;
    }
    void use() { cout << "Using: " << name << endl; }
};

int main() {
    cout << "--- unique_ptr ---" << endl;
    {
        unique_ptr<Resource> p1 = make_unique<Resource>("UniqueRes");
        p1->use();
        // unique_ptr<Resource> p2 = p1;  // ERROR: cannot copy
    } // p1 goes out of scope, Resource destroyed

    cout << "\n--- shared_ptr ---" << endl;
    {
        shared_ptr<Resource> p2 = make_shared<Resource>("SharedRes");
        cout << "Count: " << p2.use_count() << endl;
        {
            shared_ptr<Resource> p3 = p2;  // shared ownership
            cout << "Count: " << p2.use_count() << endl;
            p3->use();
        } // p3 destroyed, count decreases
        cout << "Count: " << p2.use_count() << endl;
    } // p2 destroyed, count = 0, Resource destroyed

    cout << "\nDone" << endl;
    return 0;
}

