#include <iostream>
using namespace std;

class ResizableArray {
    int* data;
    int size;
    int capacity;

    void resize() {
        capacity *= 2;
        int* newData = new int[capacity];
        for (int i = 0; i < size; i++) newData[i] = data[i];
        delete[] data;
        data = newData;
    }

public:
    ResizableArray() : size(0), capacity(4) {
        data = new int[capacity];
    }
    ~ResizableArray() { delete[] data; }

    void push(int val) {
        if (size == capacity) resize();
        data[size++] = val;
    }

    void print() {
        cout << "Elements: ";
        for (int i = 0; i < size; i++) cout << data[i] << " ";
        cout << endl;
        cout << "Capacity: " << capacity << endl;
    }
};

int main() {
    ResizableArray arr;
    for (int i = 1; i <= 6; i++) arr.push(i);
    arr.print();
    return 0;
}

#include <iostream>
using namespace std;

int** allocMatrix(int r, int c) {
    int** m = new int*[r];
    for (int i = 0; i < r; i++) m[i] = new int[c];
    return m;
}

void freeMatrix(int** m, int r) {
    for (int i = 0; i < r; i++) delete[] m[i];
    delete[] m;
}

int main() {
    int r, c;
    cin >> r >> c;
    int** a = allocMatrix(r, c);
    int** b = allocMatrix(r, c);
    int** sum = allocMatrix(r, c);

    for (int i = 0; i < r; i++)
        for (int j = 0; j < c; j++) cin >> a[i][j];
    for (int i = 0; i < r; i++)
        for (int j = 0; j < c; j++) cin >> b[i][j];
    for (int i = 0; i < r; i++)
        for (int j = 0; j < c; j++) sum[i][j] = a[i][j] + b[i][j];

    cout << "Sum:" << endl;
    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) cout << sum[i][j] << " ";
        cout << endl;
    }

    freeMatrix(a, r);
    freeMatrix(b, r);
    freeMatrix(sum, r);
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Student {
public:
    string name;
    int marks;
    Student() : name(""), marks(0) {}
    Student(string n, int m) : name(n), marks(m) {}
    void display(int idx) {
        cout << idx << ". " << name << " - " << marks << endl;
    }
};

int main() {
    int n;
    cin >> n;
    Student* students = new Student[n];
    for (int i = 0; i < n; i++) {
        string name; int marks;
        cin >> name >> marks;
        students[i] = Student(name, marks);
    }

    cout << "All Students:" << endl;
    for (int i = 0; i < n; i++) students[i].display(i + 1);

    int topIdx = 0;
    for (int i = 1; i < n; i++)
        if (students[i].marks > students[topIdx].marks) topIdx = i;
    cout << "Topper: " << students[topIdx].name << " (" << students[topIdx].marks << ")" << endl;

    delete[] students;
    return 0;
}

#include <iostream>
using namespace std;

class SafeArray {
    int* data;
    int len;
public:
    SafeArray(int n) : len(n), data(new int[n]()) {
        cout << "Array created with size " << n << endl;
    }
    ~SafeArray() {
        delete[] data;
        cout << "Array destroyed (" << len << " elements freed)" << endl;
    }
    int& operator[](int i) { return data[i]; }
    int size() const { return len; }
    void fill(int val) {
        for (int i = 0; i < len; i++) data[i] = val;
    }
    void print() {
        for (int i = 0; i < len; i++) cout << data[i] << " ";
        cout << endl;
    }
};

int main() {
    SafeArray arr(5);
    arr.fill(42);
    cout << "Filled: ";
    arr.print();
    arr[2] = 99;
    cout << "Modified: ";
    arr.print();
    // No delete needed! Destructor handles cleanup
    return 0;
}
